            aOrbiterB = RotL64((aOrbiterB * 3180788980790851487U), 19U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterJ) + 13855657291692482758U;
            aOrbiterA = (aOrbiterA ^ aOrbiterK) ^ 10548912956557830901U;
            aOrbiterA = RotL64((aOrbiterA * 14260523955604120801U), 27U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterB) + 7660180814950439184U) + aNonceWordJ;
            aOrbiterF = (aOrbiterF ^ aOrbiterH) ^ 16050354937004851995U;
