            //
            aIngress = RotL64(aScrapLaneA[((aIndex + 9672U)) & S_BLOCK1], 44U) ^ RotL64(aSource[((aIndex + 6612U)) & S_BLOCK1], 29U);
            aIngress = TwistMix64::DiffuseB(((aIngress ^ aDomainWordIngress) ^ aNonceWordA));
