            aCross = RotL64(aScrapLaneA[((S_BLOCK1 - aIndex + 10452U)) & S_BLOCK1], 47U) ^ RotL64(pSnow[((S_BLOCK1 - aIndex + 8036U)) & S_BLOCK1], 4U);
            aCross = TwistMix64::DiffuseC(((aCross ^ aDomainWordCross) ^ aNonceWordE));
