            aOrbiterI = (aWandererH + RotL64(aIngress, 41U)) + 12183001640396729460U;
            aOrbiterE = ((aWandererE + RotL64(aCross, 28U)) + RotL64(aCarry, 5U)) + 6651314953611326180U;
