            //
            aOrbiterE = (((aOrbiterE + aOrbiterD) + 302646419135419217U) + aOrbiterUpdateSaltC[((aIndex + 6U)) & S_SALT1]) + aNonceWordJ;
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 135352622397090549U;
            aOrbiterB = RotL64((aOrbiterB * 2512533316648159747U), 3U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterJ) + 14456111752067220971U;
