            //
            aOrbiterC = (aWandererF + RotL64(aIngress, 44U)) + 8862136399560229761U;
            aOrbiterD = ((aWandererH + RotL64(aPrevious, 29U)) + 12820936015991640938U) + aPhaseGOrbiterAssignSaltE[((aIndex + 20U)) & S_SALT1];
            aOrbiterJ = ((aWandererB + RotL64(aScatter, 23U)) + RotL64(aCarry, 3U)) + 14891193369474554769U;
            aOrbiterE = ((aWandererA + RotL64(aCross, 53U)) + RotL64(aCarry, 19U)) + 15779467034028384420U;
            aOrbiterB = (((aWandererE + RotL64(aPrevious, 5U)) + RotL64(aCarry, 43U)) + 1363975430147781479U) + aPhaseGOrbiterAssignSaltA[(((31U - aIndex) + 27U)) & S_SALT1];
            aOrbiterI = (aWandererJ + RotL64(aCross, 35U)) + 16243931709484158000U;
            aOrbiterF = (aWandererD + RotL64(aIngress, 11U)) + 4344024374080624313U;
            //
            aOrbiterC = (aOrbiterC + aOrbiterD) + 4797026667448876098U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterC) ^ 9774092606377198058U;
            aOrbiterJ = RotL64((aOrbiterJ * 2538603920074341409U), 19U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterC) + 13343332767800681693U) + aPhaseGOrbiterUpdateSaltC[((aIndex + 26U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 15549628804381145399U;
