            //
            aOrbiterJ = (aOrbiterJ + aOrbiterI) + 16767711367502895959U;
            aOrbiterE = (aOrbiterE ^ aOrbiterJ) ^ 16259106140711117034U;
            aOrbiterE = RotL64((aOrbiterE * 6066022210834547425U), 41U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 3112707027596412795U;
            aOrbiterD = (aOrbiterD ^ aOrbiterF) ^ 5886085097763842654U;
