            //
            aOrbiterB = (aOrbiterB + aOrbiterJ) + 8715690481452378915U;
            aOrbiterF = ((aOrbiterF ^ aOrbiterB) ^ 11138512673759668930U) ^ aPhaseGOrbiterUpdateSaltE[((aIndex + 18U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 5659077131815241799U), 13U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterF) + 10299005873617675085U) + aPhaseGOrbiterUpdateSaltF[(((31U - aIndex) + 17U)) & S_SALT1];
