            aOrbiterB = (aWandererI + RotL64(aScatter, 5U)) + 1292832376661884599U;
            aOrbiterJ = ((aWandererH + RotL64(aCross, 21U)) + RotL64(aCarry, 23U)) + 16947800033176247175U;
            //
            aOrbiterE = (aOrbiterE + aOrbiterH) + 13084931946893510939U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterE) ^ 15714524423393647294U) ^ aPhaseGOrbiterUpdateSaltC[(((31U - aIndex) + 23U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 6984561722336542109U), 5U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 1862096754494235652U;
